import pandas as pd
import numpy as np
import matplotlib.pyplot as plt

# =============================================================================
# SECTION 1: GPP State-Specific Analysis Functions
# =============================================================================

GPP_SECTION_FIELDS = {
    'usnatv1': {'SaleOptOut': True, 'SharingOptOut': True, 'TargetedAdvertisingOptOut': True, 'Gpc': True, 'state_name': 'US National'},
    'uscav1': {'SaleOptOut': True, 'SharingOptOut': True, 'TargetedAdvertisingOptOut': False, 'Gpc': True, 'state_name': 'California'},
    'uscov1': {'SaleOptOut': True, 'SharingOptOut': False, 'TargetedAdvertisingOptOut': True, 'Gpc': True, 'state_name': 'Colorado'},
    'usctv1': {'SaleOptOut': True, 'SharingOptOut': False, 'TargetedAdvertisingOptOut': True, 'Gpc': True, 'state_name': 'Connecticut'},
    'usvav1': {'SaleOptOut': True, 'SharingOptOut': False, 'TargetedAdvertisingOptOut': True, 'Gpc': False, 'state_name': 'Virginia'},
    'usutv1': {'SaleOptOut': True, 'SharingOptOut': False, 'TargetedAdvertisingOptOut': True, 'Gpc': False, 'state_name': 'Utah'},
}

def _init_counts_table():
    table = pd.DataFrame()
    table.index = ['Positive Instance Counts']
    for field in ['Sale', 'Sharing', 'TargetedAdvertising']:
        for val in [0, 1, 2]:
            for time in ['Before', 'After']:
                table[f'{field} = {val} {time}'] = [0]
    for val in [0, 1]:
        for time in ['Before', 'After']:
            table[f'Gpc = {val} {time}'] = [0]
    return table

def _count_section_data(df, section_name, table):
    def count_matches(series, pattern):
        col_exists = pd.isnull(series) == False
        return len(df[(col_exists & (series.str.contains(pattern)))])

    for time in ['Before', 'After']:
        col_name = f"{section_name}_{time.lower()}"
        if col_name not in df.columns:
            continue
        series = df[col_name]
        field_configs = [('Sale', 0), ('Sharing', 1), ('TargetedAdvertising', 2)]
        for field_short, pos in field_configs:
            for val in [0, 1, 2]:
                if pos == 0:
                    pattern = rf'^{val},[012]{{0,1}},[012]{{0,1}},[012]{{0,1}}$'
                elif pos == 1:
                    pattern = rf'^[012]{{0,1}},{val},[012]{{0,1}},[012]{{0,1}}$'
                elif pos == 2:
                    pattern = rf'^[012]{{0,1}},[012]{{0,1}},{val},[012]{{0,1}}$'
                table[f'{field_short} = {val} {time}'] += count_matches(series, pattern)
        for val in [0, 1]:
            pattern = rf'^[012]{{0,1}},[012]{{0,1}},[012]{{0,1}},{val}$'
            table[f'Gpc = {val} {time}'] += count_matches(series, pattern)
    return table

def sections_analysis_breakdown(df, state_section, sections_table_func):
    sections_df = sections_table_func(df)
    tables = {
        'national': _init_counts_table(),
        'state': _init_counts_table(),
        'other': _init_counts_table()  # For sections not relevant to current analysis
    }

    # All known state sections
    all_state_sections = ['uscav1', 'uscov1', 'usctv1', 'usvav1', 'usutv1']

    # Count US National data
    _count_section_data(sections_df, 'usnatv1', tables['national'])

    # Count state-specific data if not analyzing national
    if state_section != 'usnatv1':
        _count_section_data(sections_df, state_section, tables['state'])

    # Count "Other" sections (all state sections except the one being analyzed)
    for section in all_state_sections:
        if section != state_section:
            _count_section_data(sections_df, section, tables['other'])

    return tables

def plot_unified_section_chart(tables, state_name, state_section, field_short, time, save=False):
    """
    Creates a unified grouped horizontal bar chart showing National, State, and Other sections.

    Args:
        tables: dict with 'national', 'state', 'other' count tables
        state_name: Human-readable state name (e.g., 'Connecticut')
        state_section: Section code (e.g., 'usctv1')
        field_short: Field to plot ('Sale', 'Sharing', 'TargetedAdvertising', or 'Gpc')
        time: Time label for chart title
        save: Whether to save the figure
    """
    # Define colors for each section
    section_colors = {
        'national': '#4A90D9',  # Blue
        'state': '#D94A4A',     # Red
        'other': '#808080'      # Gray
    }

    # Get the data for each section
    def get_counts(table, field, time_label):
        if field == 'Gpc':
            return [
                table[f'{field} = 0 {time_label}']['Positive Instance Counts'],
                table[f'{field} = 1 {time_label}']['Positive Instance Counts']
            ]
        else:
            return [
                table[f'{field} = 0 {time_label}']['Positive Instance Counts'],
                table[f'{field} = 1 {time_label}']['Positive Instance Counts'],
                table[f'{field} = 2 {time_label}']['Positive Instance Counts']
            ]

    # Get Before and After counts for each section
    sections_data = {}
    for section_key in ['national', 'state', 'other']:
        sections_data[section_key] = {
            'before': get_counts(tables[section_key], field_short, 'Before'),
            'after': get_counts(tables[section_key], field_short, 'After')
        }

    # Calculate totals for each section
    totals = {
        'national': sum(sections_data['national']['before']),
        'state': sum(sections_data['state']['before']),
        'other': sum(sections_data['other']['before'])
    }

    # Create labels
    if field_short == 'Gpc':
        value_labels = ['GPC=0 (Off)', 'GPC=1 (On)']
    else:
        value_labels = ['N/A (0)', 'Did Not Opt Out (1)', 'Opted Out (2)']

    # Create the figure with grouped bars - increased width for more label space
    fig, axes = plt.subplots(1, 2, figsize=(16, 4), sharey=True)

    y_positions = np.arange(3)  # National, State, Other
    bar_height = 0.7

    section_labels = [
        f'US National\n(n={totals["national"]:,})',
        f'{state_name}\n(n={totals["state"]:,})',
        f'Other States\n(n={totals["other"]:,})'
    ]

    for ax_idx, time_label in enumerate(['Before', 'After']):
        ax = axes[ax_idx]

        # Stack bars horizontally for each section
        for sect_idx, section_key in enumerate(['national', 'state', 'other']):
            data = sections_data[section_key][time_label.lower()]
            left = 0
            for val_idx, val in enumerate(data):
                color_intensity = 0.3 + (val_idx * 0.3)  # Vary intensity
                if field_short == 'Gpc':
                    colors = ['#90dcfc', '#9ee6b0']  # Blue, Green
                else:
                    colors = ['#d6baca', '#90dcfc', '#9ee6b0']  # Pink, Blue, Green

                bar = ax.barh(sect_idx, val, bar_height, left=left,
                             color=colors[val_idx], edgecolor='white', linewidth=0.5)

                # Add value label if significant
                if val > 0:
                    text_x = left + val / 2
                    ax.text(text_x, sect_idx, f'{val:,}', ha='center', va='center',
                           fontsize=9, fontweight='bold' if val > 50 else 'normal')
                left += val

        ax.set_yticks(y_positions)
        ax.set_yticklabels(section_labels)
        ax.set_xlabel('Count')
        ax.set_title(f'{time_label} GPC', fontsize=11)
        ax.invert_yaxis()  # National at top


    # Add legend
    if field_short == 'Gpc':
        legend_labels = ['GPC Off', 'GPC On']
        legend_colors = ['#90dcfc', '#9ee6b0']
    else:
        legend_labels = ['Not Applicable', 'Did Not Opt Out', 'Opted Out']
        legend_colors = ['#d6baca', '#90dcfc', '#9ee6b0']

    legend_patches = [plt.Rectangle((0,0),1,1, facecolor=c) for c in legend_colors]

    # Adjust layout to make room for legend and title
    # top=0.82 leaves space at the top, left=0.12 ensures y-axis labels fit
    fig.subplots_adjust(left=0.12, right=0.98, top=0.82, bottom=0.15, wspace=0.1)

    fig.legend(legend_patches, legend_labels, loc='upper center', ncol=len(legend_labels),
              bbox_to_anchor=(0.5, 0.92), frameon=False)

    # Title
    field_display = {
        'Sale': 'SaleOptOut',
        'Sharing': 'SharingOptOut',
        'TargetedAdvertising': 'TargetedAdOptOut',
        'Gpc': 'GPC Signal'
    }
    fig.suptitle(f'{field_display.get(field_short, field_short)} - Section Comparison ({time})',
                fontsize=12, fontweight='bold', y=0.98)

    # plt.tight_layout()  # Removed to preserve manual layout adjustments

    if save:
        filename = f"{time.replace('/','_').replace(' ','_')}_{field_short.lower()}_unified_comparison.png"
        fig.savefig(filename, bbox_inches='tight', dpi=150)

    return fig

def plot_gpp_opt_outs_breakdown(df, state_section, save, time, colors_list, sections_table_func, plot_barh_func, plot_gpc_func):
    df_gpp = df[(pd.isnull(df['gpp_before_gpc']) == False) | (pd.isnull(df['gpp_after_gpc']) == False)]
    if len(df_gpp) == 0:
        print('No GPP graphs because no GPP data in input dataframe')
        return
    tables = sections_analysis_breakdown(df_gpp, state_section, sections_table_func)
    state_name = GPP_SECTION_FIELDS.get(state_section, {}).get('state_name', state_section)

    # Determine which sections are in "Other"
    all_state_sections = ['uscav1', 'uscov1', 'usctv1', 'usvav1', 'usutv1']
    other_sections = [s for s in all_state_sections if s != state_section]
    other_names = [GPP_SECTION_FIELDS.get(s, {}).get('state_name', s) for s in other_sections]
    other_label = f"Other States ({', '.join(other_names)})" if len(other_names) <= 2 else f"Other States ({len(other_names)} states)"

    # Sale
    print("--- Sale Analysis ---")
    # Unified comparison chart
    fig_unified = plot_unified_section_chart(tables, state_name, state_section, 'Sale', time, save)
    plt.show()

    # Individual charts
    fig_nat = plot_barh_func(tables['national'], ['After\nGPC', 'Before\nGPC'], colors_list, f'SaleOptOut (US National - usnatv1)', 'Sale', time)
    if save: fig_nat.savefig(f"{time.replace('/','_')}_usnatv1_sale_opt_out.png", bbox_inches='tight')
    plt.show()
    if GPP_SECTION_FIELDS.get(state_section, {}).get('SaleOptOut', False):
        fig_state = plot_barh_func(tables['state'], ['After\nGPC', 'Before\nGPC'], colors_list, f'SaleOptOut ({state_name} - {state_section})', 'Sale', time)
        if save: fig_state.savefig(f"{time.replace('/','_')}_{state_section}_sale_opt_out.png", bbox_inches='tight')
        plt.show()
    # Other sections - Sale
    fig_other = plot_barh_func(tables['other'], ['After\nGPC', 'Before\nGPC'], colors_list, f'SaleOptOut ({other_label})', 'Sale', time)
    if save: fig_other.savefig(f"{time.replace('/','_')}_other_sale_opt_out.png", bbox_inches='tight')
