def plot_gpp_unified_only(df, state_section, save, time, sections_table_func):
    """
    Simplified function that only generates the unified comparison charts.
    Shows National vs State vs Other on the same chart for each metric.

    Args:
        df: DataFrame with GPP data
        state_section: State section code (e.g., 'usctv1')
        save: Whether to save figures
        time: Time label for title
        sections_table_func: Function to process GPP strings into sections table
    """
    df_gpp = df[(pd.isnull(df['gpp_before_gpc']) == False) | (pd.isnull(df['gpp_after_gpc']) == False)]
    if len(df_gpp) == 0:
        print('No GPP graphs because no GPP data in input dataframe')
        return

    tables = sections_analysis_breakdown(df_gpp, state_section, sections_table_func)
    state_name = GPP_SECTION_FIELDS.get(state_section, {}).get('state_name', state_section)

    print(f"=== GPP Unified Section Comparison for {state_name} ({time}) ===\n")

    for field in ['Sale', 'Sharing', 'TargetedAdvertising', 'Gpc']:
        print(f"--- {field} Analysis ---")
        fig = plot_unified_section_chart(tables, state_name, state_section, field, time, save)
        plt.show()
        print()


def print_gpp_field_reference():
    print("=" * 80)
    print("GPP State-Specific Field Reference")
    print("=" * 80)
    print(f"{'Section':<12} {'State':<15} {'SaleOptOut':<12} {'SharingOptOut':<15} {'TargetedAdOptOut':<18} {'Gpc':<5}")
    print("-" * 80)
    for section, info in GPP_SECTION_FIELDS.items():
        sale = "✓" if info.get('SaleOptOut') else "✗"
        sharing = "✓" if info.get('SharingOptOut') else "✗"
        targeted = "✓" if info.get('TargetedAdvertisingOptOut') else "✗"
        gpc = "✓" if info.get('Gpc') else "✗"
        print(f"{section:<12} {info['state_name']:<15} {sale:<12} {sharing:<15} {targeted:<18} {gpc:<5}")
    print("=" * 80)

