# Helper function to convert worksheet name to readable time label
def worksheet_to_time_label(worksheet_name):
    """
    Converts worksheet name (e.g., 'Aug/Sept/Oct2025') to readable time label (e.g., 'Aug/Sept/Oct 2025').
    Automatically adds a space before the year if missing.
    """
    import re
    # Add a space before 4-digit year if not already present
    return re.sub(r'(\D)(\d{4})$', r'\1 \2', worksheet_name)

