def get_overlap(df, lst):
  # see if sites in lst are found in df; return which ones and how many
  total = 0
  sites_in_set = []
  for tv in lst:
    if len(df[df['Site URL'] == tv]) > 0:
      sites_in_set.append(tv)
      total += 1
    elif len(df[df['domain'] == tv[8:]]) > 0: # domain change
      sites_in_set.append(tv)
      total += 1
  sites_in_set_no_http = [] # deal with domain changes -- there's no https:// in these
  for i in sites_in_set:
    sites_in_set_no_http.append(i[8:])
  return sites_in_set, total, sites_in_set_no_http

