def opt_out_gpp(df_gpp):
  # finds full opt outs (i.e. opts out in all categories for that section)
  df = Processing_Analysis_Data.sections_table(df_gpp)
  # return df
  usnatv1_opt_out = df[(pd.isnull(df['usnatv1_after']) == False) & (df['usnatv1_after'].str.contains(r'^1,1,1,[10]$'))]
  uscav1_opt_out = df[((pd.isnull(df['uscav1_after']) == False) & (df['uscav1_after'].str.contains(r'^1,1,,[10]$')))]
  usvav1_opt_out = df[((pd.isnull(df['usvav1_after']) == False) & (df['usvav1_after'].str.contains(r'^1,,1,$')))]
  uscov1_opt_out = df[((pd.isnull(df['uscov1_after']) == False) & (df['uscov1_after'].str.contains(r'^1,,1,[10]$')))]
  usutv1_opt_out = df[((pd.isnull(df['usutv1_after']) == False) & (df['usutv1_after'].str.contains(r'^1,,1,$')))]
  usctv1_opt_out = df[((pd.isnull(df['usctv1_after']) == False) & (df['usctv1_after'].str.contains(r'^1,,1,[10]$')))]

  print(len(usnatv1_opt_out), len(uscav1_opt_out))
  concat = pd.concat([usnatv1_opt_out, uscav1_opt_out, usvav1_opt_out, uscov1_opt_out, usutv1_opt_out, usctv1_opt_out]).drop_duplicates(subset=['Site URL'])
  return concat

